const void* fmu_callback(int fmuVersion) {
    FMUModelData *modelData = (FMUModelData *)_instance;
    if(fmuVersion <= 2) {
       return (const void *)modelData->functions;
    }
    else if(fmuVersion == 3) {
       return (const void *)modelData->logMessage;
    }
    else {
       return NULL;
    }
}

